class Solution:
    def mergeTwoLists(self, list1: Optional[ListNode], list2: Optional[ListNode]) -> Optional[ListNode]:
        if list1 is None and list2 is None:
            return None

        result = ListNode()
        head = result
        while list1 is not None and list2 is not None:

            if list1.val > list2.val:
                temp = list2
                list2 = list2.next
            else:
                temp = list1
                list1 = list1.next

            result.next = temp
            result = result.next

        if list1 is None:
            result.next = list2
        else:
            result.next = list1


        return head.next
